const { Discovery, Cam } = require('onvif');
ipcMain.handle('onvif:discover', () => new Promise(resolve => {
  const found = [];
  Discovery.probe({ timeout: 4000, resolve: false }, (err, matches) => {
    if (err) return resolve({ error: 'Discovery failed: ' + err.message });
    for (const m of matches || []) found.push(parseProbeMatch(m));
    resolve({ devices: found.filter(Boolean) });
  });
}));

